double_t compute_rate() {
	double_t R3_R13_r = scenario2_3(k_R3_R13, int_to_double(R13), int_to_double(R13Levels), true, int_to_double(R3), int_to_double(R3Levels), true);
	double_t R23_R13_r = scenario1(k_R23_R13, int_to_double(R23), int_to_double(R23Levels), true);
	double_t R13_R13_r = scenario1(k_R13_R13, int_to_double(R13), int_to_double(R13Levels), true);
	if (R3_R13_r.b == 0 && R3 > 0) { //If the downstream reactant (R) is the only reason for the inactivity of the reaction R3_R13 (note that R is actually R13), consider the reaction as still available (recomputing the rate as the one closest to the current situation), to avoid significant errors in performing the next update to R. We want to avoid considering any other reaction active on R as the only one possible during the whole next delta increment to R.
		//Using the following rate is not very precise, but makes for a much more precise total rate than we would get if considering the reaction as inactive (especially with low levels of granularity for R, i.e. small values of MAX)
		R3_R13_r = scenario2_3(k_R3_R13, int_to_double(1), int_to_double(R13Levels), true, int_to_double(R3), int_to_double(R3Levels), true);
	}
	//R3_R13.T = _ANIMO_round(inverse(R3_R13_r));
	//R23_R13.T = _ANIMO_round(inverse(R23_R13_r));
	//R13_R13.T = _ANIMO_round(inverse(R13_R13_r));
	return subtract(add(subtract(zero, R3_R13_r), R23_R13_r), R13_R13_r);
}

